using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Tool Implementations ---

/// <summary>Tools the research agent can invoke during its investigation loop.</summary>
static class ResearchTools
{
    private static readonly HttpClient s_http = new();
    private static readonly List<string> s_notes = [];

    [Description("Search the web for information on a query. Returns a list of result snippets.")]
    public static async Task<string> WebSearch(
        [Description("The search query string")] string query)
    {
        Console.WriteLine($"  🔍 Searching: \"{query}\"");

        // Use the free DuckDuckGo Instant Answer API (no key required).
        var encoded = Uri.EscapeDataString(query);
        var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

        try
        {
            var doc = await s_http.GetFromJsonAsync<JsonDocument>(url);
            var root = doc!.RootElement;

            var results = new List<string>();

            // Abstract / summary
            var abs = root.GetProperty("Abstract").GetString();
            if (!string.IsNullOrWhiteSpace(abs))
                results.Add($"[Summary] {abs} (source: {root.GetProperty("AbstractSource").GetString()})");

            // Related topics
            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(5))
                {
                    var text = topic.TryGetProperty("Text", out var t) ? t.GetString() : null;
                    if (!string.IsNullOrWhiteSpace(text))
                        results.Add($"[Related] {text}");
                }
            }

            if (results.Count == 0)
                return "No results found. Try a different or more specific query.";

            return string.Join("\n\n", results);
        }
        catch (Exception ex)
        {
            return $"Search failed ({ex.Message}). Try rephrasing the query.";
        }
    }

    [Description("Save a research note for later reference. Use this to record key findings as you research.")]
    public static string SaveNote(
        [Description("The note content to save")] string note)
    {
        s_notes.Add(note);
        Console.WriteLine($"  📝 Note saved (#{s_notes.Count})");
        return $"Note #{s_notes.Count} saved.";
    }

    [Description("Retrieve all saved research notes.")]
    public static string GetNotes()
    {
        if (s_notes.Count == 0)
            return "No notes saved yet.";

        return string.Join("\n", s_notes.Select((n, i) => $"Note #{i + 1}: {n}"));
    }
}

// --- Agent Loop ---

var topic = args.Length > 0 ? string.Join(' ', args) : "quantum computing recent breakthroughs 2026";

Console.WriteLine($"🔬 Research Agent Starting...");
Console.WriteLine($"📋 Topic: {topic}\n");

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run the agent.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()   // automatically invokes tools
    .Build();

var tools = new[]
{
    AIFunctionFactory.Create(ResearchTools.WebSearch),
    AIFunctionFactory.Create(ResearchTools.SaveNote),
    AIFunctionFactory.Create(ResearchTools.GetNotes),
};

var systemPrompt = """
    You are a research agent. Your goal is to thoroughly research the given topic
    and produce a well-structured summary.

    Workflow:
    1. Search the web with several varied queries to gather broad information.
    2. Save important findings as notes using the SaveNote tool.
    3. After gathering enough information (at least 2-3 searches), retrieve your
       notes and write a comprehensive summary.

    Always cite your sources when possible. Be factual and concise.
    """;

var messages = new List<ChatMessage>
{
    new(ChatRole.System, systemPrompt),
    new(ChatRole.User, $"Please research the following topic and provide a summary:\n\n{topic}")
};

var options = new ChatOptions { Tools = [.. tools] };

const int maxTurns = 10;
ChatResponse? response = null;

for (var turn = 0; turn < maxTurns; turn++)
{
    response = await chatClient.GetResponseAsync(messages, options);

    // Append the full response into the conversation history.
    messages.AddMessages(response);

    // If the model made tool calls, the FunctionInvocation middleware already
    // executed them and appended results. Loop so the model can continue.
    var hasToolCalls = response.Messages
        .Any(m => m.Contents.OfType<FunctionCallContent>().Any());

    if (!hasToolCalls)
        break; // Model produced a final text answer.
}

Console.WriteLine("\n════════════════════════════════════════");
Console.WriteLine("  📄  RESEARCH SUMMARY");
Console.WriteLine("════════════════════════════════════════\n");

var finalText = response?.Text ?? "Agent produced no output.";
Console.WriteLine(finalText);

